    [CharacterType.MAGIC]: { name: 'Magic', color: '#d946ef' },
    [CharacterType.ANIMAL]: { name: 'Beast', color: '#d97706' },
    [CharacterType.DARKNESS]: { name: 'Void', color: '#4c1d95' },
