};

// ... SkinPreview Component (Same as before) ...
interface SkinPreviewProps {
    color: string;
    visuals?: SkinVisuals;
}

const SkinPreview: React.FC<SkinPreviewProps> = ({ color, visuals }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Clear
        ctx.clearRect(0, 0, canvas.width, canvas.height);

        const cx = canvas.width / 2;
        const cy = canvas.height / 2 + 10;

        ctx.strokeStyle = color;
        ctx.fillStyle = color;
        ctx.lineWidth = 3;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';

        // Apply visual effects
        if (visuals?.effect === 'NEON_OUTLINE') {
            ctx.shadowColor = color;
            ctx.shadowBlur = 10;
        } else if (visuals?.effect === 'FIRE') {
            ctx.shadowColor = 'orange';
            ctx.shadowBlur = 15;
        } else if (visuals?.effect === 'GLITCH') {
            ctx.translate(Math.random()*2 - 1, 0);
        }

        // Draw Back Accessories (Simpler now)
        if (visuals?.backAccessory === 'CAPE') {
            ctx.fillStyle = '#900';
            ctx.beginPath();
            ctx.moveTo(cx - 5, cy - 25);
            ctx.lineTo(cx + 5, cy - 25);
            ctx.lineTo(cx + 10, cy + 30);
            ctx.lineTo(cx - 10, cy + 30);
            ctx.fill();
        } else if (visuals?.backAccessory === 'WINGS') {
            ctx.fillStyle = 'rgba(255,255,255,0.5)';
            if (color === '#450a0a') ctx.fillStyle = '#000'; // Demon wings
            ctx.beginPath();
            ctx.moveTo(cx, cy - 20);
            ctx.quadraticCurveTo(cx - 40, cy - 50, cx - 30, cy + 10);
            ctx.quadraticCurveTo(cx - 10, cy, cx, cy - 10);
            ctx.fill();
            ctx.beginPath();
            ctx.moveTo(cx, cy - 20);
            ctx.quadraticCurveTo(cx + 40, cy - 50, cx + 30, cy + 10);
            ctx.quadraticCurveTo(cx + 10, cy, cx, cy - 10);
            ctx.fill();
        } else if (visuals?.backAccessory === 'SCARF') {
            ctx.strokeStyle = '#333';
            ctx.lineWidth = 4;
            ctx.beginPath();
            ctx.moveTo(cx - 5, cy - 22);
            ctx.quadraticCurveTo(cx - 20, cy - 20, cx - 25, cy - 10);
            ctx.stroke();
        }

        // Draw Body (Standard Stickman)
        ctx.strokeStyle = color; // Reset stroke color
        ctx.lineWidth = 3;

        ctx.beginPath();
        // Legs
        ctx.moveTo(cx, cy + 10); ctx.lineTo(cx - 10, cy + 40);
        ctx.moveTo(cx, cy + 10); ctx.lineTo(cx + 10, cy + 40);
        // Torso
        ctx.moveTo(cx, cy - 20); ctx.lineTo(cx, cy + 10);
        // Arms (Pose)
        ctx.moveTo(cx, cy - 20); ctx.lineTo(cx - 15, cy + 5);
        ctx.moveTo(cx, cy - 20); ctx.lineTo(cx + 15, cy + 5);
        ctx.stroke();

        // Draw Head
        ctx.beginPath();
        ctx.arc(cx, cy - 30, 10, 0, Math.PI * 2);
        ctx.stroke();

        // Draw Face Accessories
        if (visuals?.faceAccessory === 'MASK_NINJA') {
            ctx.fillStyle = '#111';
            ctx.beginPath(); ctx.arc(cx, cy - 30, 9, 0, Math.PI*2); ctx.fill();
            ctx.fillStyle = '#fff'; // Eyes
            ctx.fillRect(cx - 4, cy - 32, 3, 2);
            ctx.fillRect(cx + 1, cy - 32, 3, 2);
        } else if (visuals?.faceAccessory === 'VISOR') {
            ctx.fillStyle = '#0ff';
            ctx.fillRect(cx - 6, cy - 34, 12, 4);
        } else if (visuals?.faceAccessory === 'MASK_ONI') {
            ctx.fillStyle = '#fff';
            ctx.beginPath(); ctx.moveTo(cx-8, cy-35); ctx.lineTo(cx+8, cy-35); ctx.lineTo(cx, cy-22); ctx.fill();
        } else if (visuals?.faceAccessory === 'EYEPATCH') {
            ctx.fillStyle = '#000';
            ctx.beginPath(); ctx.arc(cx-3, cy-32, 3, 0, Math.PI*2); ctx.fill();
            ctx.beginPath(); ctx.moveTo(cx-3, cy-32); ctx.lineTo(cx+8, cy-40); ctx.stroke();
        } else if (visuals?.faceAccessory === 'GLASSES') {
            ctx.fillStyle = '#000';
            ctx.fillRect(cx - 6, cy - 33, 12, 3);
        }

        // Draw Head Accessories
        if (visuals?.accessory === 'HAT_STRAW') {
            ctx.fillStyle = '#d4a373';
            ctx.beginPath(); ctx.ellipse(cx, cy - 38, 20, 5, 0, 0, Math.PI*2); ctx.fill();
            ctx.beginPath(); ctx.arc(cx, cy - 40, 8, Math.PI, 0); ctx.fill();
        } else if (visuals?.accessory === 'HALO') {
            ctx.strokeStyle = '#ff0';
            ctx.lineWidth = 2;
            ctx.beginPath(); ctx.ellipse(cx, cy - 45, 12, 4, 0, 0, Math.PI*2); ctx.stroke();
        } else if (visuals?.accessory === 'HORNS') {
            ctx.fillStyle = '#fff';
            ctx.beginPath(); ctx.moveTo(cx - 5, cy - 38); ctx.lineTo(cx - 10, cy - 48); ctx.lineTo(cx - 2, cy - 39); ctx.fill();
            ctx.beginPath(); ctx.moveTo(cx + 5, cy - 38); ctx.lineTo(cx + 10, cy - 48); ctx.lineTo(cx + 2, cy - 39); ctx.fill();
        } else if (visuals?.accessory === 'CROWN') {
            ctx.fillStyle = 'gold';
            ctx.beginPath(); ctx.moveTo(cx-8, cy-38); ctx.lineTo(cx-8, cy-48); ctx.lineTo(cx-4, cy-42); ctx.lineTo(cx, cy-48); ctx.lineTo(cx+4, cy-42); ctx.lineTo(cx+8, cy-48); ctx.lineTo(cx+8, cy-38); ctx.fill();
        } else if (visuals?.accessory === 'HAT_GENERAL') {
            ctx.fillStyle = '#1e293b';
            ctx.fillRect(cx - 10, cy - 45, 20, 10);
            ctx.fillStyle = '#000';
            ctx.fillRect(cx - 12, cy - 38, 24, 4); // Brim
        } else if (visuals?.accessory === 'HAT_COWBOY') {
            ctx.fillStyle = '#8b4513';
            ctx.beginPath(); ctx.ellipse(cx, cy - 40, 16, 4, 0, 0, Math.PI*2); ctx.fill(); // Brim
            ctx.beginPath(); ctx.arc(cx, cy - 44, 8, Math.PI, 0); ctx.fill(); // Top
        } else if (visuals?.accessory === 'HAT_WIZARD') {
            ctx.fillStyle = '#4c1d95';
            ctx.beginPath(); ctx.moveTo(cx - 12, cy - 38); ctx.lineTo(cx + 12, cy - 38); ctx.lineTo(cx, cy - 58); ctx.fill();
        } else if (visuals?.accessory === 'HEADPHONES') {
            ctx.strokeStyle = '#333'; ctx.lineWidth = 4;
            ctx.beginPath(); ctx.arc(cx, cy - 30, 12, Math.PI, 0); ctx.stroke();
            ctx.fillStyle = '#333';
            ctx.fillRect(cx - 14, cy - 34, 4, 8);
            ctx.fillRect(cx + 10, cy - 34, 4, 8);
        }

    }, [color, visuals]);

    return <canvas ref={canvasRef} width={100} height={100} className="w-full h-full object-contain" />;
};


export const DojoUpgrades: React.FC<DojoUpgradesProps> = ({ characterProgress, onUnlockSkin, onEquipSkin, onUnlockAbility, onEquipAbility, onBack }) => {
    const [selectedChar, setSelectedChar] = useState<CharacterType>(CharacterType.NINJA);
