                                    : 'border-transparent hover:bg-gray-800/50'
                                }`}
                            >
                                <div className="font-bold text-sm uppercase" style={{ color: isSelected ? info.color : '#888' }}>
                                    {info.name}
                                </div>
                                <div className="flex justify-between text-xs text-gray-500 mt-1">
                                    <span>Lvl {charProg.level}</span>
                                    <span>{charProg.masteryPoints} Pts</span>
                                </div>
                            </button>
                        );
                    })}
                </div>

                {/* Main Content */}
                <div className="flex-1 p-8 overflow-y-auto bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')]">

                    {/* Character Header */}
