                        <div className="w-24 h-24 rounded-full border-4 shadow-neon flex items-center justify-center bg-black" style={{ borderColor: charInfo.color }}>
                            <div className="text-4xl" style={{ color: charInfo.color }}>🥋</div>
                        </div>
                        <div>
                            <h2 className="text-6xl font-black italic text-white uppercase tracking-tighter" style={{ textShadow: `0 0 20px ${charInfo.color}` }}>
                                {charInfo.name}
                            </h2>
                            <div className="text-xl text-gray-400 flex gap-4 mt-2">
                                <span className="bg-gray-800 px-3 py-1 rounded border border-gray-700 text-white">Level {progress.level}</span>
                                <span className="bg-yellow-900/30 px-3 py-1 rounded border border-yellow-700 text-yellow-500">
                                    {progress.masteryPoints} Mastery Points Available
                                </span>
                            </div>
                        </div>
                    </div>

                    {/* Tabs */}
                    <div className="flex gap-4 mb-6 border-b border-gray-700 pb-1">
                        <button 
                            onClick={() => setTab('SKINS')}
                            className={`px-6 py-2 font-bold uppercase tracking-widest transition-all ${tab === 'SKINS' ? 'text-white border-b-2 border-white' : 'text-gray-500 hover:text-gray-300'}`}
                        >
                            Skins
