                    </div>

                    {tab === 'SKINS' && (
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                            {/* Default Skin Card */}
                            <div className={`p-6 rounded-xl border-2 flex flex-col gap-4 relative overflow-hidden transition-all ${!progress.equippedSkin ? 'border-green-500 bg-green-900/20' : 'border-gray-700 bg-gray-900'}`}>
                                <div className="flex justify-between items-start">
                                    <h4 className="text-2xl font-bold text-white uppercase">Default</h4>
                                    {!progress.equippedSkin && <span className="text-green-500 font-bold text-xs uppercase border border-green-500 px-2 py-1 rounded">Equipped</span>}
