                                <div className="flex justify-between items-start">
                                    <h4 className="text-2xl font-bold text-white uppercase">Default Special</h4>
                                    {!progress.equippedAbility && <span className="text-green-500 font-bold text-xs uppercase border border-green-500 px-2 py-1 rounded">Equipped</span>}
                                </div>
                                <div className="w-full h-32 bg-black rounded-lg flex items-center justify-center border border-gray-800 text-4xl">
                                    ⚡
                                </div>
                                <p className="text-gray-400 text-sm h-10">Standard character ability.</p>
                                <button 
                                    onClick={() => onEquipAbility(selectedChar, null)}
                                    disabled={!progress.equippedAbility}
                                    className={`w-full py-3 font-bold uppercase rounded tracking-widest ${!progress.equippedAbility ? 'bg-gray-700 text-gray-500 cursor-default' : 'bg-white text-black hover:bg-gray-200'}`}
                                >
                                    {progress.equippedAbility ? "Equip" : "Equipped"}
