              const winTimer = setTimeout(() => {
                  if (spinResultP2 && onSelectBoth) onSelectBoth(spinResult, spinResultP2);
                  else onSelect(spinResult);
              }, 1200);
              return () => clearTimeout(winTimer);
          }, 1000);
          return () => clearTimeout(timer);
      }
  }, [spinState, spinResult]);

