            <div className="absolute inset-0 bg-black/95 z-50 flex flex-col items-center justify-center animate-fade-in">
                <div className="text-4xl font-black text-white italic mb-12 animate-pulse tracking-widest uppercase">
                    {spinState === 'SPINNING' ? "Searching Database..." : "FIGHTERS FOUND"}
                </div>

                <div className="flex gap-12 items-center">
                    <div className="text-center">
                        <div className="text-xl text-gray-400 mb-4 font-bold tracking-widest">{isPvp && playerNumber === 1 ? "PLAYER 1" : "SELECTED"}</div>
                        <div className={`w-64 h-64 border-4 rounded-2xl flex items-center justify-center bg-gray-900 transition-all duration-300 ${spinState === 'SHOW_WINNER' ? 'border-neon-blue scale-110 shadow-[0_0_30px_#00f3ff]' : 'border-gray-700'}`}>
