      d.hp -= dmg; 
      if(d.hp<=0) d.state='DEAD';
      createParticles(d.x, d.y, '#fff', 5);
  }; 
  const triggerFinisher = (p: Entity, v: Entity) => {
      finisherRef.current = { active: true, timer: 300, type: p.type, victimX: v.x, victimY: v.y };
      p.state = 'FINISHER'; v.state = 'STUNNED';
  };

  const executeSpecial = (ent: Entity, opponents: Entity[], overrideType?: CharacterType) => {
      if (ent.state === 'DEAD') return;
      const type = overrideType || ent.type;

      if (!overrideType && ent.abilityId) {
          if (ent.abilityId === 'ninja_shuriken') {
              ent.state = 'ATTACK';
              for(let i=0; i<5; i++) {
                  const angle = (i-2) * 0.2;
                  projectilesRef.current.push({
                      x: ent.x, y: ent.y,
                      vx: (ent.facingRight?15:-15) * Math.cos(angle), vy: 15 * Math.sin(angle),
                      radius: 5, color: '#fff', life: 60, damage: 8, homing: false,
                      ownerId: ent.id, isPlayerTeam: ent.isPlayer, specialType: 'BUG'
                  });
              }
              return;
          } else if (ent.abilityId === 'titan_boulder') {
              ent.state = 'ATTACK';
              const dir = ent.facingRight ? 1 : -1;
              projectilesRef.current.push({
                  x: ent.x + dir*40, y: ent.y, vx: dir * 15, vy: -5,
                  radius: 40, color: '#5c4033', life: 100, damage: 40, homing: false,
                  ownerId: ent.id, isPlayerTeam: ent.isPlayer, specialType: 'ROCKET'
              });
              return;
          } else if (ent.abilityId === 'inferno_fireball') {
              ent.state = 'ATTACK';
              projectilesRef.current.push({
                  x: ent.x, y: ent.y, vx: ent.facingRight?20:-20, vy: 0,
                  radius: 30, color: '#ff4400', life: 80, damage: 35, homing: true,
                  ownerId: ent.id, isPlayerTeam: ent.isPlayer, specialType: 'SOLAR_FLARE'
              });
              return;
          } else if (ent.abilityId === 'ronin_dash') {
              const target = opponents[0];
              if (target) {
                  ent.x = target.x + (ent.facingRight ? 100 : -100);
                  ent.facingRight = !ent.facingRight;
                  applyDamage(ent, target, 25);
                  target.state = 'STUNNED';
                  slashesRef.current.push({x1: ent.x, y1: ent.y, x2: target.x, y2: target.y, width: 5, color: '#fff', life: 0.5});
                  playSound('swing');
              }
              return;
          } else if (ent.abilityId === 'volt_thunder') {
              const target = opponents[0] || ent;
              projectilesRef.current.push({
                  x: target.x, y: -100, vx: 0, vy: 30, radius: 10, color: '#ff0', life: 50, damage: 30, homing: false,
                  ownerId: ent.id, isPlayerTeam: ent.isPlayer, specialType: 'FIRE_PILLAR', width: 20, height: 800
              });
              shakeRef.current = 10;
              return;
          }
      }

      if (ent.type !== CharacterType.CHAOS) {
          ent.state = 'ABILITY';
          ent.specialCooldown = ent.maxSpecialCooldown;
          ent.vy = 0; ent.vx = 0;
      }

      const target = opponents.reduce((prev, curr) => Math.abs(ent.x - curr.x) < Math.abs(ent.x - prev.x) ? curr : prev, opponents[0]);
      if (!target && gameMode !== GameState.PLAYING_WAVE && gameMode !== GameState.PLAYING_FREERUN && opponents.length > 0) return;

      if (type === CharacterType.VIKING) {
          ent.state = 'ATTACK';
          projectilesRef.current.push({
              x: ent.x, y: ent.y - 20, vx: (ent.facingRight?15:-15), vy: -15,
              radius: 40, color: '#fff', life: 100, damage: 35, homing: false,
              ownerId: ent.id, isPlayerTeam: ent.isPlayer, specialType: 'AXE', rotation: 0
          });
      } else if (type === CharacterType.PIRATE) {
          ent.state = 'ATTACK';
          for(let i=0; i<5; i++) {
              projectilesRef.current.push({
                  x: (target?.x || ent.x) + (Math.random()-0.5)*300, y: -50, vx: 0, vy: 15,
                  radius: 15, color: '#000', life: 100, damage: 20, homing: false,
                  ownerId: ent.id, isPlayerTeam: ent.isPlayer, specialType: 'CANNONBALL', delay: i*10
              });
          }
      } else if (type === CharacterType.CYBORG) {
          if (!target) return;
          ent.x = target.x + (ent.facingRight ? 100 : -100);
          ent.facingRight = !ent.facingRight;
          slashesRef.current.push({ x1: ent.x, y1: ent.y, x2: target.x, y2: target.y, width: 5, color: '#e879f9', life: 0.5 });
          if (checkCollision(ent, target, 50)) {
              applyDamage(ent, target, 25);
              target.state = 'STUNNED';
          }
          ent.state = 'IDLE';
      } else if (type === CharacterType.NINJA) {
          ent.vx = ent.facingRight ? 40 : -40;
      } else if (type === CharacterType.TITAN) {
          ent.vy = 30;
      } else {
          // Fallback
          createParticles(ent.x, ent.y, ent.color, 20);
          ent.state = 'IDLE';
      }
  };

  const drawStickman = (ctx: CanvasRenderingContext2D, e: Entity, overrideTime?: number) => {
      // (Full implementation of drawStickman logic with accessory rendering)
      if (introTimerRef.current > 60 && e.type === CharacterType.NINJA) return;
      const isFinisherLoser = finisherRef.current.active && finisherRef.current.type !== e.type && (!e.isPlayer || finisherRef.current.type !== playerRef.current.type);

      let drawColor = e.color;
      if (isFinisherLoser && finisherRef.current.type === CharacterType.ZOMBIE) drawColor = '#65a30d';

      ctx.strokeStyle = drawColor;
      ctx.fillStyle = drawColor;
      ctx.lineWidth = 3;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.shadowBlur = 15;
      ctx.shadowColor = drawColor;

      const cx = e.x + e.width / 2;
      const cy = e.y + e.height / 2;
      const currentTime = overrideTime || Date.now();
      const idleT = currentTime / 300; 

      ctx.save();
      ctx.translate(cx, cy);
      ctx.rotate(e.rotation);
      if (!e.facingRight) ctx.scale(-1, 1);

      let visuals: any = null;
      if (e.skinId) {
          const skin = SHOP_SKINS.find(s => s.id === e.skinId);
          if (skin) visuals = skin.visuals;
      }

      if (visuals) {
          ctx.save();
          if (visuals.effect === 'NEON_OUTLINE') { ctx.shadowBlur = 20; ctx.shadowColor = drawColor; }
          if (visuals.effect === 'FIRE') { ctx.shadowBlur = 20; ctx.shadowColor = 'orange'; }
          if (visuals.effect === 'GHOST') ctx.globalAlpha = 0.6;
          if (visuals.effect === 'GLITCH') ctx.translate(Math.random()*4-2, 0);

          if (visuals.backAccessory === 'CAPE') {
              ctx.fillStyle = '#900';
              ctx.beginPath(); ctx.moveTo(-5, -25); ctx.lineTo(5, -25); ctx.lineTo(15, 35); ctx.lineTo(-15, 35); ctx.fill();
          } else if (visuals.backAccessory === 'WINGS') {
              ctx.fillStyle = drawColor === '#450a0a' ? '#000' : 'rgba(255,255,255,0.5)';
              ctx.beginPath(); ctx.ellipse(-20, -10, 35, 10, Math.PI/4, 0, Math.PI*2); ctx.fill();
              ctx.beginPath(); ctx.ellipse(20, -10, 35, 10, -Math.PI/4, 0, Math.PI*2); ctx.fill();
          } else if (visuals.backAccessory === 'SCARF') {
              ctx.strokeStyle = '#333'; ctx.lineWidth = 5;
              ctx.beginPath(); ctx.moveTo(-5, -22); ctx.quadraticCurveTo(-25, -20, -30, -5); ctx.stroke();
          }
          ctx.restore();
      }

      // Base Body
      ctx.beginPath(); ctx.moveTo(0, -20); ctx.lineTo(0, 10); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(0, 10); ctx.lineTo(-10, 40); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(0, 10); ctx.lineTo(10, 40); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(0, -20); ctx.lineTo(-15, 0); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(0, -20); ctx.lineTo(15, 0); ctx.stroke();
      ctx.beginPath(); ctx.arc(0, -30, 10, 0, Math.PI*2); ctx.stroke();

      if (visuals) {
          ctx.save();
          if (visuals.faceAccessory === 'VISOR') { ctx.fillStyle = '#0ff'; ctx.fillRect(-6, -34, 12, 4); }
          else if (visuals.faceAccessory === 'EYEPATCH') { ctx.fillStyle = '#000'; ctx.beginPath(); ctx.arc(-3, -32, 3, 0, Math.PI*2); ctx.fill(); }
          else if (visuals.faceAccessory === 'MASK_ONI') { ctx.fillStyle = '#fff'; ctx.beginPath(); ctx.moveTo(-8, -35); ctx.lineTo(8, -35); ctx.lineTo(0, -22); ctx.fill(); }
          else if (visuals.faceAccessory === 'GLASSES') { ctx.fillStyle = '#000'; ctx.fillRect(-6, -33, 12, 3); }
          else if (visuals.faceAccessory === 'MASK_NINJA') { ctx.fillStyle = '#111'; ctx.beginPath(); ctx.arc(0, -30, 9, 0, Math.PI*2); ctx.fill(); ctx.fillStyle = '#fff'; ctx.fillRect(-4, -32, 3, 2); ctx.fillRect(1, -32, 3, 2); }

          if (visuals.accessory === 'HAT_STRAW') { ctx.fillStyle = '#d4a373'; ctx.beginPath(); ctx.ellipse(0, -38, 20, 5, 0, 0, Math.PI*2); ctx.fill(); ctx.beginPath(); ctx.arc(0, -40, 8, Math.PI, 0); ctx.fill(); }
          else if (visuals.accessory === 'HAT_COWBOY') { ctx.fillStyle = '#8b4513'; ctx.beginPath(); ctx.ellipse(0, -40, 16, 4, 0, 0, Math.PI*2); ctx.fill(); ctx.beginPath(); ctx.arc(0, -44, 8, Math.PI, 0); ctx.fill(); }
          else if (visuals.accessory === 'HAT_WIZARD') { ctx.fillStyle = '#4c1d95'; ctx.beginPath(); ctx.moveTo(-12, -38); ctx.lineTo(12, -38); ctx.lineTo(0, -58); ctx.fill(); }
          else if (visuals.accessory === 'HALO') { ctx.strokeStyle = '#ff0'; ctx.beginPath(); ctx.ellipse(0, -45, 12, 4, 0, 0, Math.PI*2); ctx.stroke(); }
          else if (visuals.accessory === 'HORNS') { ctx.fillStyle = '#fff'; ctx.beginPath(); ctx.moveTo(-5, -38); ctx.lineTo(-10, -48); ctx.lineTo(-2, -39); ctx.fill(); ctx.beginPath(); ctx.moveTo(5, -38); ctx.lineTo(10, -48); ctx.lineTo(2, -39); ctx.fill(); }
          else if (visuals.accessory === 'CROWN') { ctx.fillStyle = 'gold'; ctx.beginPath(); ctx.moveTo(-8, -38); ctx.lineTo(-8, -48); ctx.lineTo(-4, -42); ctx.lineTo(0, -48); ctx.lineTo(4, -42); ctx.lineTo(8, -48); ctx.lineTo(8, -38); ctx.fill(); }
          else if (visuals.accessory === 'HAT_GENERAL') { ctx.fillStyle = '#1e293b'; ctx.fillRect(-10, -45, 20, 10); ctx.fillStyle='#000'; ctx.fillRect(-12, -38, 24, 4); }
          else if (visuals.accessory === 'HEADPHONES') { ctx.strokeStyle = '#333'; ctx.lineWidth = 4; ctx.beginPath(); ctx.arc(0, -30, 12, Math.PI, 0); ctx.stroke(); ctx.fillStyle = '#333'; ctx.fillRect(-14, -34, 4, 8); ctx.fillRect(10, -34, 4, 8); }

          ctx.restore();
      }

      ctx.restore();
  };

  const updateEntity = (ent: Entity, keys: Record<string, boolean> | null, opponents: Entity[], isControlled: boolean = false) => {
      // Logic for physics and particles based on skin
      if (ent.skinId) {
          const skin = SHOP_SKINS.find(s => s.id === ent.skinId);
          if (skin?.visuals?.effect === 'SPARKLE' && Math.random() < 0.1) createParticles(ent.x+20, ent.y+40, '#fff', 1);
          if (skin?.visuals?.effect === 'SLIME' && Math.random() < 0.1) createParticles(ent.x+20, ent.y+80, '#0f0', 1);
      }

      ent.vy += GRAVITY;
      ent.x += ent.vx; ent.y += ent.vy;

      if (ent.y > GROUND_Y - ent.height) { ent.y = GROUND_Y - ent.height; ent.vy = 0; ent.vx *= FRICTION; }
      else ent.vx *= AIR_DRAG;

      if (ent.x < 0) ent.x = 0;
      if (ent.x > CANVAS_WIDTH - ent.width) ent.x = CANVAS_WIDTH - ent.width;

      if (ent.specialCooldown > 0) ent.specialCooldown--;
  };

  const animate = (time: number) => {
      const ctx = canvasRef.current?.getContext('2d');
      if (!ctx) return;
      ctx.fillStyle = '#0a0a0a';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // Player
      updateEntity(playerRef.current, keysRef.current, opponentsRef.current, true);
      drawStickman(ctx, playerRef.current);

      // Opponents
      opponentsRef.current.forEach(op => {
          updateEntity(op, keysRef.current, [playerRef.current], false);
          drawStickman(ctx, op);
      });

      // Projectiles
      projectilesRef.current.forEach((p, i) => {
          if (p.life <= 0) { projectilesRef.current.splice(i, 1); return; }
          p.x += p.vx; p.y += p.vy; p.life--;
          ctx.fillStyle = p.color;
          if (p.specialType === 'AXE') {
              ctx.save(); ctx.translate(p.x, p.y); ctx.rotate(p.rotation || 0);
              ctx.fillStyle = '#fff'; ctx.fillRect(-10, -30, 20, 60); ctx.restore();
              p.rotation = (p.rotation || 0) + 0.2;
              p.vy += 0.5; // Gravity for axe
          } else if (p.specialType === 'CANNONBALL') {
              ctx.fillStyle = '#000'; ctx.beginPath(); ctx.arc(p.x, p.y, p.radius, 0, Math.PI*2); ctx.fill();
              if (p.y > GROUND_Y) { 
                  p.life = 0; 
                  addShockwave(p.x, GROUND_Y, '#000');
                  createParticles(p.x, GROUND_Y, '#ff4400', 10);
                  // AOE Damage
                  [playerRef.current, ...opponentsRef.current].forEach(ent => {
                      if (Math.hypot(ent.x - p.x, ent.y - GROUND_Y) < 100) {
                          applyDamage({type: playerCharType, isPlayer: p.isPlayerTeam} as any, ent, 20);
                      }
                  });
              }
          } else {
              ctx.beginPath(); ctx.arc(p.x, p.y, p.radius, 0, Math.PI*2); ctx.fill();
          }
      });

      requestRef.current = requestAnimationFrame(animate);
  };

  useEffect(() => {
    if (!audioCtxRef.current) audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    playerRef.current = createEntity(playerCharType, true, 200, 300, 'p1');
    opponentsRef.current = [];
    if (gameMode !== GameState.PLAYING_FREERUN && gameMode !== GameState.PLAYING_WAVE) {
        opponentsRef.current.push(createEntity(cpuCharType || CharacterType.NINJA, false, CANVAS_WIDTH-200, 300, 'cpu1'));
    }
    const kd = (e:any) => keysRef.current[e.key] = true;
    const ku = (e:any) => keysRef.current[e.key] = false;
    window.addEventListener('keydown', kd); window.addEventListener('keyup', ku);
    requestRef.current = requestAnimationFrame(animate);
    return () => { window.removeEventListener('keydown', kd); window.removeEventListener('keyup', ku); cancelAnimationFrame(requestRef.current); };
  }, []);

  const addPortalPair = () => {}; 

  return <canvas ref={canvasRef} width={CANVAS_WIDTH} height={CANVAS_HEIGHT} className="bg-gradient-to-b from-gray-900 to-black w-full h-full object-contain" />;
};
