  const ghostsRef = useRef<Ghost[]>([]);
  const portalsRef = useRef<Portal[]>([]);
  const portalCooldownRef = useRef<number>(0);
  const keysRef = useRef<Record<string, boolean>>({});
  const finisherRef = useRef<{active: boolean, timer: number, type: CharacterType | null, victimX: number, victimY: number}>({active: false, timer: 0, type: null, victimX: 0, victimY: 0});
  const slashesRef = useRef<{x1: number, y1: number, x2: number, y2: number, width: number, color: string, life: number, decay?: number}[]>([]);

  const waveStateRef = useRef({ nextSpawnTime: 0, active: gameMode === GameState.PLAYING_WAVE, killCount: 0, wave: 1, achievedWave5: false });

  const createEntity = (type: CharacterType, isPlayer: boolean, x: number, y: number, id: string): Entity => {
      const stats = CHAR_STATS[type];
      let hpMult = 1;
      let calculatedSpeed = stats.speed;
      let calculatedPower = stats.power;
      let calculatedHp = stats.hp;
      let entityColor = stats.color;
      let skinId = undefined;
      let abilityId = undefined;

      if (isPlayer && characterProgress) {
          const prog = characterProgress[type];
          if (prog) {
              if (prog.equippedSkin) {
                  const skin = SHOP_SKINS.find(s => s.id === prog.equippedSkin);
                  if (skin) {
                      skinId = skin.id;
                      if (skin.colorOverride) entityColor = skin.colorOverride;
                  }
              }
              if (prog.equippedAbility) abilityId = prog.equippedAbility;
          }
      }

      if (type === CharacterType.CHAOS) {
          calculatedSpeed = 5 + Math.floor(Math.random() * 12);
          calculatedPower = 10 + Math.floor(Math.random() * 15); 
          calculatedHp = 90 + Math.floor(Math.random() * 100); 
      }

      if (!isPlayer) hpMult = 1.3; 
      if (gameMode === GameState.TOURNAMENT_LADDER) {
          if (tournamentRound === 1) hpMult = 1.2;
          if (tournamentRound === 2) hpMult = 1.5;
          if (tournamentRound === 3) hpMult = 2.0;
      }
      calculatedHp *= hpMult;
      if (gameMode === GameState.PLAYING_WAVE && !isPlayer) calculatedHp = 20 + (waveStateRef.current.wave * 5); 

      return {
          id, x, y, vx: 0, vy: 0, width: 40, height: 80, color: entityColor,
          hp: calculatedHp, maxHp: calculatedHp, speed: calculatedSpeed, power: calculatedPower,
          isPlayer, facingRight: isPlayer, state: 'IDLE',
          comboCount: 0, lastAttackTime: 0, specialCooldown: 0, maxSpecialCooldown: stats.maxSpecialCooldown,
          type, jumpCount: 0, onWall: false, rotation: 0, vr: 0,
          deadHandled: false, frozen: false, attackVariant: 0, abilityTimer: 0, 
          specialChainWindow: 0, specialChainStep: 0, skinId, abilityId
      };
  };

  const playSound = (type: string) => { 
      if (!audioCtxRef.current) return;
      if (audioCtxRef.current.state === 'suspended') audioCtxRef.current.resume();
      const osc = audioCtxRef.current.createOscillator();
      const gain = audioCtxRef.current.createGain();
      osc.connect(gain);
      gain.connect(audioCtxRef.current.destination);
      const now = audioCtxRef.current.currentTime;

      osc.frequency.setValueAtTime(200, now);
      osc.frequency.exponentialRampToValueAtTime(10, now + 0.1);
      gain.gain.setValueAtTime(0.1, now);
      gain.gain.exponentialRampToValueAtTime(0.01, now + 0.1);
      osc.start(now);
      osc.stop(now + 0.1);
  };

  const createParticles = (x: number, y: number, color: string, count: number, speed: number = 10) => {
