          } else if (ent.abilityId === 'glacier_wall') {
              ent.state = 'ATTACK';
              const x = ent.x + (ent.facingRight ? 60 : -60);
              for(let i=0; i<3; i++) {
                  projectilesRef.current.push({
                      x: x + (i-1)*20, y: GROUND_Y, vx: 0, vy: 0,
