      }

      if (!isPlayer) hpMult = 1.3; 
      if (gameMode === GameState.TOURNAMENT_LADDER) {
          if (tournamentRound === 1) hpMult = 1.2;
          if (tournamentRound === 2) hpMult = 1.5;
          if (tournamentRound === 3) hpMult = 2.0;
      }
      calculatedHp *= hpMult;
      if (gameMode === GameState.PLAYING_WAVE && !isPlayer) calculatedHp = 20 + (waveStateRef.current.wave * 5); 

      return {
          id, x, y, vx: 0, vy: 0, width: 40, height: 80, color: entityColor,
