                            <div className="text-4xl" style={{ color: charInfo.color }}>🥋</div>
                        </div>
                        <div>
                            <h2 className="text-6xl font-black italic text-white uppercase tracking-tighter" style={{ textShadow: `0 0 20px ${charInfo.color}` }}>{charInfo.name}</h2>
