                                    <div key={skin.id} className={`p-6 rounded-xl border-2 flex flex-col gap-4 relative overflow-hidden transition-all ${isEquipped ? 'border-green-500 bg-green-900/20' : 'border-gray-700 bg-gray-900'}`}>
