export interface SpecialResult {
    projectiles?: any[]; // Using any to avoid circular dependency issues with Projectile type duplication
    particles?: { x: number, y: number, color: string, count: number, speed?: number }[];
    sound?: 'special' | 'heavy' | 'laser' | 'ice' | 'burn' | 'wind' | 'bug' | 'time' | 'hit' | 'swing' | 'jump' | 'finisher' | 'gun';
    shockwave?: { x: number, y: number, color: string };
    screenTint?: { color: string, alpha: number };
    shake?: number;
    stateUpdate?: Partial<Entity>;
    slashes?: { x1: number, y1: number, x2: number, y2: number, width: number, color: string, life: number, decay?: number }[];
    darkenScreen?: number;
    hitStop?: number;
    flash?: number;
    comboText?: { text: string, x: number, y: number, isBig?: boolean };
}

export const getSpecialMove = (
    attacker: Entity, 
    opponents: Entity[], 
    groundY: number
): SpecialResult | null => {

    // Find closest target
    const target = opponents.reduce((prev, curr) => {
        return Math.abs(attacker.x - curr.x) < Math.abs(attacker.x - prev.x) ? curr : prev;
    }, opponents[0]);

    const type = attacker.type;
    const facingDir = attacker.facingRight ? 1 : -1;

    // --- GRAVITY REVERSAL ---
    if (type === CharacterType.GRAVITY) {
        const newInvertedState = !attacker.gravityInverted;
        return {
            sound: 'special',
            particles: [{ x: attacker.x, y: attacker.y, color: '#2e1065', count: 20 }],
            stateUpdate: { 
                gravityInverted: newInvertedState,
                vy: newInvertedState ? 15 : -15, // Push off surface
                state: 'ABILITY' 
            },
            comboText: { text: newInvertedState ? "GRAVITY UP!" : "GRAVITY DOWN!", x: attacker.x, y: attacker.y - 50, isBig: true }
        };
    }

    // --- HYPNO ---
    if (type === 'HYPNO' as CharacterType) { // Type assertion if enum not updated yet
        return {
            sound: 'time',
            particles: [{ x: attacker.x, y: attacker.y, color: '#d946ef', count: 30 }],
            screenTint: { color: 'rgba(217, 70, 239, 0.4)', alpha: 0.6 },
            stateUpdate: { state: 'ATTACK' }
            // Note: Effect on opponent handled in BrawlGame via opponents loop if needed, 
            // or we can handle it here by returning a 'targetsUpdate' if we expand the interface.
            // For now, simple state/visuals here, complex logic remains or we rely on projectiles.
        };
    }

    // --- VIKING ---
    if (type === CharacterType.VIKING) {
        return {
            sound: 'heavy',
            stateUpdate: { state: 'ATTACK' },
            projectiles: [{
                x: attacker.x, y: attacker.y - 20, vx: facingDir * 12, vy: -20,
                radius: 40, color: '#fff', life: 100, damage: 35, homing: false,
                ownerId: attacker.id, isPlayerTeam: attacker.isPlayer, specialType: 'AXE', rotation: 0
            }]
        };
    }

    // --- PIRATE ---
    if (type === CharacterType.PIRATE) {
        const projs = [];
        const centerX = target ? target.x : (attacker.x + facingDir * 300);
        for(let i=0; i<5; i++) {
            projs.push({
