        return {
            sound: 'heavy',
            stateUpdate: { state: 'ATTACK' },
            projectiles: projs
        };
    }

    // --- CYBER ---
    if (type === CharacterType.CYBER && target) {
        const destX = target.x + (attacker.facingRight ? 150 : -150);
        return {
