                x: destX, 
                y: target.y, 
                facingRight: !attacker.facingRight 
            },
            slashes: [{
                x1: attacker.x, y1: attacker.y, x2: destX, y2: target.y,
                width: 8, color: '#e879f9', life: 0.5
            }],
            particles: [{ x: target.x, y: target.y, color: '#e879f9', count: 20 }],
            // Cyber collision logic is specific, handled in component for now via slash check
        };
    }

    // --- DEFAULT PROJECTILES MAPPING ---
    // Moving logic for simple projectile characters to cleanup BrawlGame
    if (type === CharacterType.INFERNO) {
        const projs = [];
        const targetX = target ? target.x : attacker.x + (facingDir * 200);
        for(let i=0; i<3; i++) {
            projs.push({
