                radius: 50, color: '#ff3333', life: 60, damage: 15, homing: false, 
                ownerId: attacker.id, isPlayerTeam: attacker.isPlayer, specialType: 'FIRE_PILLAR', delay: 20 + i*15,
                width: 80, height: 400
            });
        }
        return {
            sound: 'burn',
            stateUpdate: { state: 'ATTACK', vy: -10 },
            shake: 25,
            screenTint: { color: 'rgba(255, 50, 0, 0.4)', alpha: 0.5 },
            particles: [{ x: targetX, y: -50, color: '#ffaa00', count: 30, speed: 20 }], // Rain
            projectiles: projs
        };
    }

    if (type === CharacterType.NINJA) {
        return {
            stateUpdate: { vx: facingDir * 40 },
            particles: [{ x: attacker.x, y: attacker.y, color: '#00f3ff', count: 15 }],
            hitStop: 5
        };
    }

    // Fallback for others not fully refactored yet to prevent breaking
    return null;
};
