import React, { useRef, useEffect, useState } from 'react';
import { Entity, CharacterType, CharacterStats, Particle, GameState, SHOP_SKINS, SHOP_ABILITIES, CharacterProgress } from '../types';
import { CHARACTERS as CHAR_STATS } from './Stats';
import { getSpecialMove, SpecialResult } from './Specials';

interface BrawlGameProps {
  playerCharType: CharacterType;
  cpuCharType?: CharacterType; 
  gameMode: GameState;
  onGameOver: (winner: 'PLAYER' | 'CPU') => void;
  tournamentRound?: number; 
  onBack: () => void;
  onUnlockAchievement: (id: string) => void;
  characterProgress?: Record<CharacterType, CharacterProgress>;
}

interface Shockwave {
    x: number; y: number; radius: number; maxRadius: number; color: string; life: number; width: number;
}

interface Projectile {
    x: number; y: number; vx: number; vy: number; radius: number; color: string; life: number; damage: number; homing: boolean; ownerId: string; isPlayerTeam: boolean;
    specialType?: 'FIRE_PILLAR' | 'ICE_SPIKE' | 'VOID_CUT' | 'EARTH_SPIKE' | 'BLACK_HOLE' | 'SOLAR_FLARE' | 'MINE' | 'ROCKET' | 'BULLET' | 'BUG' | 'BONE' | 'TORNADO' | 'SYMBIOTE' | 'TOXIC_PUKE' | 'PHOTON_RAY' | 'AXE' | 'CANNONBALL'; 
    width?: number; height?: number; delay?: number; hitIds?: string[]; rotation?: number; 
}

interface Ghost extends Entity { life: number; snapshotTime: number; }

interface Portal {
    id: string; x: number; y: number; targetX: number; targetY: number; color: string; pairId: string;
}

const CANVAS_WIDTH = 1200;
const CANVAS_HEIGHT = 700;
const GRAVITY = 0.6;
const FRICTION = 0.85; 
const AIR_DRAG = 0.96; 
const GROUND_Y = 550;
const CEILING_Y = 50; 
const WALL_SLIDE_SPEED = 1.5;

export const BrawlGame: React.FC<BrawlGameProps> = ({ playerCharType, cpuCharType, gameMode, onGameOver, tournamentRound = 1, onBack, onUnlockAchievement, characterProgress }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [playerHealth, setPlayerHealth] = useState(100);
  const [specialCooldown, setSpecialCooldown] = useState(0); 
  const [p2SpecialCooldown, setP2SpecialCooldown] = useState(0); 
