  const introTimerRef = useRef(180);

  const playerRef = useRef<Entity>({} as Entity);
  const opponentsRef = useRef<Entity[]>([]);
  const alliesRef = useRef<Entity[]>([]);

  const particlesRef = useRef<Particle[]>([]);
  const shockwavesRef = useRef<Shockwave[]>([]);
  const projectilesRef = useRef<Projectile[]>([]); 
  const shakeRef = useRef<number>(0); 
  const hitStopRef = useRef<number>(0);
  const flashRef = useRef<number>(0);
  const darkenScreenRef = useRef<number>(0);
  const screenTintRef = useRef<{color: string, alpha: number} | null>(null);
  const comboTextRef = useRef<{text: string, x: number, y: number, life: number, scale: number}[]>([]);
  const ghostsRef = useRef<Ghost[]>([]);
  const portalsRef = useRef<Portal[]>([]);
  const portalCooldownRef = useRef<number>(0);
  const keysRef = useRef<Record<string, boolean>>({});
  const finisherRef = useRef<{active: boolean, timer: number, type: CharacterType | null, victimX: number, victimY: number}>({active: false, timer: 0, type: null, victimX: 0, victimY: 0});
  const slashesRef = useRef<{x1: number, y1: number, x2: number, y2: number, width: number, color: string, life: number, decay?: number}[]>([]);

  const waveStateRef = useRef({ nextSpawnTime: 0, active: gameMode === GameState.PLAYING_WAVE, killCount: 0, wave: 1, achievedWave5: false });

  const createEntity = (type: CharacterType, isPlayer: boolean, x: number, y: number, id: string): Entity => {
      const stats = CHAR_STATS[type];
      let hpMult = 1;
      let calculatedSpeed = stats.speed;
      let calculatedPower = stats.power;
      let calculatedHp = stats.hp;
      let entityColor = stats.color;
      let skinId: string | undefined = undefined;
      let abilityId: string | undefined = undefined;

      if (isPlayer && characterProgress) {
          const prog = characterProgress[type];
          if (prog) {
              if (prog.equippedSkin) {
                  const skin = SHOP_SKINS.find(s => s.id === prog.equippedSkin);
                  if (skin) {
                      skinId = skin.id;
                      if (skin.colorOverride) entityColor = skin.colorOverride;
                  }
              }
              if (prog.equippedAbility) abilityId = prog.equippedAbility;
          }
      }

      if (type === CharacterType.CHAOS) {
          calculatedSpeed = 5 + Math.floor(Math.random() * 12);
          calculatedPower = 10 + Math.floor(Math.random() * 15); 
          calculatedHp = 90 + Math.floor(Math.random() * 100); 
      }

      if (!isPlayer) hpMult = 1.3; 
      if (gameMode === GameState.TOURNAMENT_LADDER) {
          if (tournamentRound === 1) hpMult = 1.2;
          if (tournamentRound === 2) hpMult = 1.5;
          if (tournamentRound === 3) hpMult = 2.0;
      }
      calculatedHp *= hpMult;
      if (gameMode === GameState.PLAYING_WAVE && !isPlayer) calculatedHp = 20 + (waveStateRef.current.wave * 5); 

      return {
          id, x, y, vx: 0, vy: 0, width: 40, height: 80, color: entityColor,
          hp: calculatedHp, maxHp: calculatedHp, speed: calculatedSpeed, power: calculatedPower,
          isPlayer, facingRight: isPlayer, state: 'IDLE',
          comboCount: 0, lastAttackTime: 0, specialCooldown: 0, maxSpecialCooldown: stats.maxSpecialCooldown,
          type, jumpCount: 0, onWall: false, rotation: 0, vr: 0,
          deadHandled: false, frozen: false, attackVariant: 0, abilityTimer: 0, 
          specialChainWindow: 0, specialChainStep: 0, skinId, abilityId, reversedControlsTimer: 0, gravityInverted: false
      };
  };

  const playSound = (type: string) => { 
      if (!audioCtxRef.current) return;
      if (audioCtxRef.current.state === 'suspended') audioCtxRef.current.resume();
      const osc = audioCtxRef.current.createOscillator();
      const gain = audioCtxRef.current.createGain();
      osc.connect(gain);
      gain.connect(audioCtxRef.current.destination);
      const now = audioCtxRef.current.currentTime;

      osc.frequency.setValueAtTime(200, now);
      osc.frequency.exponentialRampToValueAtTime(10, now + 0.1);
      gain.gain.setValueAtTime(0.1, now);
      gain.gain.exponentialRampToValueAtTime(0.01, now + 0.1);
      osc.start(now);
      osc.stop(now + 0.1);
  };

  const createParticles = (x: number, y: number, color: string, count: number, speed: number = 10) => {
    for (let i = 0; i < count; i++) {
      particlesRef.current.push({ x, y, vx: (Math.random() - 0.5) * speed, vy: (Math.random() - 0.5) * speed, life: 1.0, color, size: Math.random() * 5 + 2 });
    }
  };
  const addShockwave = (x: number, y: number, color: string) => { shockwavesRef.current.push({ x, y, radius: 10, maxRadius: 120, color, life: 1.0, width: 10 }); };
  const showComboText = (txt: string, x: number, y: number, isBig: boolean = false) => { comboTextRef.current.push({ text: txt, x, y, life: 1.0, scale: isBig ? 1.5 : 1.0 }); };
  const checkCollision = (attacker: Entity, defender: Entity, rangeBonus: number = 0) => {
    if (defender.state === 'DEAD' || defender.state === 'FINISHER') return false;
    const range = attacker.width + 50 + rangeBonus; 
    const dx = Math.abs(attacker.x - defender.x);
    const dy = Math.abs(attacker.y - defender.y);
    return dx < range && dy < 90 && ((attacker.x < defender.x && attacker.facingRight) || (attacker.x > defender.x && !attacker.facingRight) || dx < 40);
  };
  const applyDamage = (a: Entity, d: Entity, dmg: number) => { 
      d.hp -= dmg; 
      if(d.hp<=0) d.state='DEAD';
      createParticles(d.x, d.y, '#fff', 5);
  }; 
  const triggerFinisher = (p: Entity, v: Entity) => {
      finisherRef.current = { active: true, timer: 300, type: p.type, victimX: v.x, victimY: v.y };
      p.state = 'FINISHER'; v.state = 'STUNNED';
  };

  const executeSpecial = (ent: Entity, opponents: Entity[], overrideType?: CharacterType) => {
      if (ent.state === 'DEAD') return;
      const type = overrideType || ent.type;

      if (!overrideType && ent.abilityId) {
          // Keep existing custom unlocked abilities in BrawlGame for now if simple
          if (ent.abilityId === 'ninja_shuriken') {
              ent.state = 'ATTACK';
              for(let i=0; i<5; i++) {
                  const angle = (i-2) * 0.2;
                  projectilesRef.current.push({
                      x: ent.x, y: ent.y,
                      vx: (ent.facingRight?15:-15) * Math.cos(angle), vy: 15 * Math.sin(angle),
                      radius: 5, color: '#fff', life: 60, damage: 8, homing: false,
                      ownerId: ent.id, isPlayerTeam: ent.isPlayer, specialType: 'BUG'
                  });
              }
              return;
          } 
          // ... (Other AbilityIds remain here or can be moved to Specials later) ...
          else if (ent.abilityId === 'ronin_dash') {
              const target = opponents[0];
              if (target) {
                  ent.x = target.x + (ent.facingRight ? 100 : -100);
                  ent.facingRight = !ent.facingRight;
                  applyDamage(ent, target, 25);
                  target.state = 'STUNNED';
                  slashesRef.current.push({x1: ent.x, y1: ent.y, x2: target.x, y2: target.y, width: 5, color: '#fff', life: 0.5});
                  playSound('swing');
              }
              return;
          } 
      }

      if (ent.type !== CharacterType.CHAOS) {
          ent.state = 'ABILITY';
          ent.specialCooldown = ent.maxSpecialCooldown;
          ent.vy = 0; ent.vx = 0;
      }

      const target = opponents.reduce((prev, curr) => Math.abs(ent.x - curr.x) < Math.abs(ent.x - prev.x) ? curr : prev, opponents[0]);
      if (!target && gameMode !== GameState.PLAYING_WAVE && gameMode !== GameState.PLAYING_FREERUN && opponents.length > 0) return;

      // Delegate to Specials.tsx
      const specialResult = getSpecialMove(ent, opponents, GROUND_Y);

      if (specialResult) {
          if (specialResult.sound) playSound(specialResult.sound);
          if (specialResult.particles) {
              specialResult.particles.forEach(p => createParticles(p.x, p.y, p.color, p.count, p.speed));
          }
          if (specialResult.projectiles) {
              projectilesRef.current.push(...specialResult.projectiles);
          }
          if (specialResult.stateUpdate) {
              Object.assign(ent, specialResult.stateUpdate);
          }
          if (specialResult.shockwave) addShockwave(specialResult.shockwave.x, specialResult.shockwave.y, specialResult.shockwave.color);
          if (specialResult.screenTint) screenTintRef.current = specialResult.screenTint;
          if (specialResult.shake) shakeRef.current = specialResult.shake;
          if (specialResult.slashes) slashesRef.current.push(...specialResult.slashes);
          if (specialResult.darkenScreen) darkenScreenRef.current = specialResult.darkenScreen;
          if (specialResult.hitStop) hitStopRef.current = specialResult.hitStop;
          if (specialResult.flash) flashRef.current = specialResult.flash;
          if (specialResult.comboText) showComboText(specialResult.comboText.text, specialResult.comboText.x, specialResult.comboText.y, specialResult.comboText.isBig);

          if (type === CharacterType.HYPNO) {
              opponents.forEach(op => {
                  op.reversedControlsTimer = 300; 
                  createParticles(op.x, op.y, '#d946ef', 20);
                  showComboText("CONFUSED!", op.x, op.y - 50, true);
              });
          }
          return; // Handled by Specials.tsx
      }

      // Fallback for older characters not moved to Specials.tsx yet (preserving existing logic)
      if (type === CharacterType.TITAN) {
          ent.vy = 30;
      } else if (type === CharacterType.CYBORG) {
          if (!target) return;
          ent.x = target.x + (ent.facingRight ? 100 : -100);
          ent.facingRight = !ent.facingRight;
          slashesRef.current.push({ x1: ent.x, y1: ent.y, x2: target.x, y2: target.y, width: 5, color: '#e879f9', life: 0.5 });
          if (checkCollision(ent, target, 50)) {
              applyDamage(ent, target, 25);
              target.state = 'STUNNED';
          }
          ent.state = 'IDLE';
      } else {
          // Generic
          createParticles(ent.x, ent.y, ent.color, 20);
          ent.state = 'IDLE';
      }
  };

  const drawStickman = (ctx: CanvasRenderingContext2D, e: Entity, overrideTime?: number) => {
      if (introTimerRef.current > 60 && e.type === CharacterType.NINJA) return;
      const isFinisherLoser = finisherRef.current.active && finisherRef.current.type !== e.type && (!e.isPlayer || finisherRef.current.type !== playerRef.current.type);

      let drawColor = e.color;
      if (isFinisherLoser && finisherRef.current.type === CharacterType.ZOMBIE) drawColor = '#65a30d';

      ctx.strokeStyle = drawColor;
      ctx.fillStyle = drawColor;
      ctx.lineWidth = 3;
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.shadowBlur = 15;
      ctx.shadowColor = drawColor;

      const cx = e.x + e.width / 2;
      const cy = e.y + e.height / 2;
      const currentTime = overrideTime || Date.now();
      const idleT = currentTime / 300; 

      ctx.save();
      ctx.translate(cx, cy);
      ctx.rotate(e.rotation);
      if (!e.facingRight) ctx.scale(-1, 1);

      if (e.gravityInverted) {
          ctx.save();
          ctx.translate(e.x + e.width/2, e.y + e.height/2);
          ctx.scale(1, -1);
          ctx.translate(-(e.x + e.width/2), -(e.y + e.height/2));
      }

      let visuals: any = null;
      if (e.skinId) {
          const skin = SHOP_SKINS.find(s => s.id === e.skinId);
          if (skin) visuals = skin.visuals;
      }

      if (visuals) {
          ctx.save();
          if (visuals.effect === 'NEON_OUTLINE') { ctx.shadowBlur = 20; ctx.shadowColor = drawColor; }
          if (visuals.effect === 'FIRE') { ctx.shadowBlur = 20; ctx.shadowColor = 'orange'; }
          if (visuals.effect === 'GHOST') ctx.globalAlpha = 0.6;
          if (visuals.effect === 'GLITCH') ctx.translate(Math.random()*4-2, 0);

          if (visuals.backAccessory === 'CAPE') {
              ctx.fillStyle = '#900';
              ctx.beginPath(); ctx.moveTo(-5, -25); ctx.lineTo(5, -25); ctx.lineTo(15, 35); ctx.lineTo(-15, 35); ctx.fill();
          } else if (visuals.backAccessory === 'WINGS') {
              ctx.fillStyle = drawColor === '#450a0a' ? '#000' : 'rgba(255,255,255,0.5)';
              ctx.beginPath(); ctx.ellipse(-20, -10, 35, 10, Math.PI/4, 0, Math.PI*2); ctx.fill();
              ctx.beginPath(); ctx.ellipse(20, -10, 35, 10, -Math.PI/4, 0, Math.PI*2); ctx.fill();
          } else if (visuals.backAccessory === 'SCARF') {
              ctx.strokeStyle = '#333'; ctx.lineWidth = 5;
              ctx.beginPath(); ctx.moveTo(-5, -22); ctx.quadraticCurveTo(-25, -20, -30, -5); ctx.stroke();
          }
          ctx.restore();
      }

      ctx.beginPath(); ctx.moveTo(0, -20); ctx.lineTo(0, 10); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(0, 10); ctx.lineTo(-10, 40); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(0, 10); ctx.lineTo(10, 40); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(0, -20); ctx.lineTo(-15, 0); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(0, -20); ctx.lineTo(15, 0); ctx.stroke();
      ctx.beginPath(); ctx.arc(0, -30, 10, 0, Math.PI*2); ctx.stroke();

      if (e.reversedControlsTimer && e.reversedControlsTimer > 0) {
          ctx.fillStyle = '#d946ef';
          ctx.font = 'bold 20px monospace';
          ctx.fillText("?", 0, -50 + Math.sin(idleT*5)*5);
          ctx.fillText("?", 15, -40 + Math.cos(idleT*5)*5);
      }

      if (visuals) {
          ctx.save();
          if (visuals.faceAccessory === 'VISOR') { ctx.fillStyle = '#0ff'; ctx.fillRect(-6, -34, 12, 4); }
          else if (visuals.faceAccessory === 'EYEPATCH') { ctx.fillStyle = '#000'; ctx.beginPath(); ctx.arc(-3, -32, 3, 0, Math.PI*2); ctx.fill(); }
          else if (visuals.faceAccessory === 'MASK_ONI') { ctx.fillStyle = '#fff'; ctx.beginPath(); ctx.moveTo(-8, -35); ctx.lineTo(8, -35); ctx.lineTo(0, -22); ctx.fill(); }
          else if (visuals.faceAccessory === 'GLASSES') { ctx.fillStyle = '#000'; ctx.fillRect(-6, -33, 12, 3); }
          else if (visuals.faceAccessory === 'MASK_NINJA') { ctx.fillStyle = '#111'; ctx.beginPath(); ctx.arc(0, -30, 9, 0, Math.PI*2); ctx.fill(); ctx.fillStyle = '#fff'; ctx.fillRect(-4, -32, 3, 2); ctx.fillRect(1, -32, 3, 2); }

          if (visuals.accessory === 'HAT_STRAW') { ctx.fillStyle = '#d4a373'; ctx.beginPath(); ctx.ellipse(0, -38, 20, 5, 0, 0, Math.PI*2); ctx.fill(); ctx.beginPath(); ctx.arc(0, -40, 8, Math.PI, 0); ctx.fill(); }
          else if (visuals.accessory === 'HAT_COWBOY') { ctx.fillStyle = '#8b4513'; ctx.beginPath(); ctx.ellipse(0, -40, 16, 4, 0, 0, Math.PI*2); ctx.fill(); ctx.beginPath(); ctx.arc(0, -44, 8, Math.PI, 0); ctx.fill(); }
          else if (visuals.accessory === 'HAT_WIZARD') { ctx.fillStyle = '#4c1d95'; ctx.beginPath(); ctx.moveTo(-12, -38); ctx.lineTo(12, -38); ctx.lineTo(0, -58); ctx.fill(); }
          else if (visuals.accessory === 'HALO') { ctx.strokeStyle = '#ff0'; ctx.beginPath(); ctx.ellipse(0, -45, 12, 4, 0, 0, Math.PI*2); ctx.stroke(); }
          else if (visuals.accessory === 'HORNS') { ctx.fillStyle = '#fff'; ctx.beginPath(); ctx.moveTo(-5, -38); ctx.lineTo(-10, -48); ctx.lineTo(-2, -39); ctx.fill(); ctx.beginPath(); ctx.moveTo(5, -38); ctx.lineTo(10, -48); ctx.lineTo(2, -39); ctx.fill(); }
          else if (visuals.accessory === 'CROWN') { ctx.fillStyle = 'gold'; ctx.beginPath(); ctx.moveTo(-8, -38); ctx.lineTo(-8, -48); ctx.lineTo(-4, -42); ctx.lineTo(0, -48); ctx.lineTo(4, -42); ctx.lineTo(8, -48); ctx.lineTo(8, -38); ctx.fill(); }
          else if (visuals.accessory === 'HAT_GENERAL') { ctx.fillStyle = '#1e293b'; ctx.fillRect(-10, -45, 20, 10); ctx.fillStyle='#000'; ctx.fillRect(-12, -38, 24, 4); }
          else if (visuals.accessory === 'HEADPHONES') { ctx.strokeStyle = '#333'; ctx.lineWidth = 4; ctx.beginPath(); ctx.arc(0, -30, 12, Math.PI, 0); ctx.stroke(); ctx.fillStyle = '#333'; ctx.fillRect(-14, -34, 4, 8); ctx.fillRect(10, -34, 4, 8); }

          ctx.restore();
      }

      ctx.restore();
      if (e.gravityInverted) ctx.restore();
  };

  const updateEntity = (ent: Entity, keys: Record<string, boolean> | null, opponents: Entity[], isControlled: boolean = false) => {
      if (ent.reversedControlsTimer && ent.reversedControlsTimer > 0) ent.reversedControlsTimer--;

      if (ent.specialCooldown > 0) ent.specialCooldown--;

      if (ent.gravityInverted) {
          ent.vy -= GRAVITY; 
          if (Math.random() < 0.1) createParticles(ent.x + ent.width/2, ent.y, '#2e1065', 1);
      } else {
          ent.vy += GRAVITY; 
      }

      ent.x += ent.vx; ent.y += ent.vy;

      const onGround = !ent.gravityInverted && ent.y > GROUND_Y - ent.height;
      const onCeiling = ent.gravityInverted && ent.y < CEILING_Y;

      if (onGround) { 
          ent.y = GROUND_Y - ent.height; ent.vy = 0; ent.vx *= FRICTION; ent.jumpCount = 0; 
      } else if (onCeiling) {
          ent.y = CEILING_Y; ent.vy = 0; ent.vx *= FRICTION; ent.jumpCount = 0;
      } else {
          ent.vx *= AIR_DRAG;
      }

      if (ent.x < 0) ent.x = 0;
      if (ent.x > CANVAS_WIDTH - ent.width) ent.x = CANVAS_WIDTH - ent.width;

      // Input Logic with Reversal
      let input = { left: false, right: false, up: false, attack: false, special: false };
      if (isControlled && keys) {
          let l = keys['ArrowLeft'] || keys['a'] || keys['A'];
          let r = keys['ArrowRight'] || keys['d'] || keys['D'];

          if (ent.reversedControlsTimer && ent.reversedControlsTimer > 0) {
              const temp = l; l = r; r = temp;
          }

          input.left = l; 
          input.right = r;
          input.up = keys['ArrowUp'] || keys['w'] || keys['W'];
          input.attack = keys['z'] || keys['Z'];
          input.special = keys['x'] || keys['X'];
      }

      // Logic for physics and particles based on skin
      if (ent.skinId) {
          const skin = SHOP_SKINS.find(s => s.id === ent.skinId);
          if (skin?.visuals?.effect === 'SPARKLE' && Math.random() < 0.1) createParticles(ent.x+20, ent.y+40, '#fff', 1);
          if (skin?.visuals?.effect === 'SLIME' && Math.random() < 0.1) createParticles(ent.x+20, ent.y+80, '#0f0', 1);
      }

      if (isControlled) {
          const acc = 1.5;
          if (input.right) { ent.vx += acc; ent.facingRight = true; ent.state = 'RUN'; }
          if (input.left) { ent.vx -= acc; ent.facingRight = false; ent.state = 'RUN'; }

          if (input.up && ent.jumpCount < 2) {
              if (!keys || !keys['jump_held_' + ent.id]) {
                  if(keys) keys['jump_held_' + ent.id] = true;
                  ent.vy = ent.gravityInverted ? 20 : -20; 
                  ent.jumpCount++;
                  playSound('jump');
              }
          } else if (!input.up && keys) {
              keys['jump_held_' + ent.id] = false;
          }

          if (input.special && ent.specialCooldown <= 0) executeSpecial(ent, opponents);
      }
  };

  const animate = (time: number) => {
      const ctx = canvasRef.current?.getContext('2d');
      if (!ctx) return;
      ctx.fillStyle = '#0a0a0a';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      // Player
      updateEntity(playerRef.current, keysRef.current, opponentsRef.current, true);
      drawStickman(ctx, playerRef.current);

      // Opponents
      opponentsRef.current.forEach(op => {
          updateEntity(op, keysRef.current, [playerRef.current], false);
          drawStickman(ctx, op);
      });

      // Projectiles
      projectilesRef.current.forEach((p, i) => {
          if (p.life <= 0) { projectilesRef.current.splice(i, 1); return; }
          p.x += p.vx; p.y += p.vy; p.life--;
          ctx.fillStyle = p.color;
          if (p.specialType === 'AXE') {
              ctx.save(); ctx.translate(p.x, p.y); ctx.rotate(p.rotation || 0);
              ctx.fillStyle = '#fff'; ctx.fillRect(-10, -30, 20, 60); ctx.restore();
              p.rotation = (p.rotation || 0) + 0.2;
              p.vy += 0.5; 
          } else if (p.specialType === 'CANNONBALL') {
              ctx.fillStyle = '#000'; ctx.beginPath(); ctx.arc(p.x, p.y, p.radius, 0, Math.PI*2); ctx.fill();
              if (p.y > GROUND_Y) { p.life = 0; addShockwave(p.x, GROUND_Y, '#000'); }
          } else {
              ctx.beginPath(); ctx.arc(p.x, p.y, p.radius, 0, Math.PI*2); ctx.fill();
          }
      });

      requestRef.current = requestAnimationFrame(animate);
  };

  useEffect(() => {
    if (!audioCtxRef.current) audioCtxRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
    playerRef.current = createEntity(playerCharType, true, 200, 300, 'p1');
    opponentsRef.current = [];
    if (gameMode !== GameState.PLAYING_FREERUN && gameMode !== GameState.PLAYING_WAVE) {
        // Ensure stats exist for CPU (especially GOD character)
        const cpuType = cpuCharType || CharacterType.NINJA;
        opponentsRef.current.push(createEntity(cpuType, false, CANVAS_WIDTH-200, 300, 'cpu1'));
    }
    const kd = (e:any) => keysRef.current[e.key] = true;
    const ku = (e:any) => keysRef.current[e.key] = false;
    window.addEventListener('keydown', kd); window.addEventListener('keyup', ku);
    requestRef.current = requestAnimationFrame(animate);
    return () => { window.removeEventListener('keydown', kd); window.removeEventListener('keyup', ku); cancelAnimationFrame(requestRef.current); };
  }, []);

  const addPortalPair = () => {}; 

  return <canvas ref={canvasRef} width={CANVAS_WIDTH} height={CANVAS_HEIGHT} className="bg-gradient-to-b from-gray-900 to-black w-full h-full object-contain" />;
};
