               });
           }
           ent.state = 'IDLE';
      }
      else if (type === CharacterType.BONE) {
           ent.vy = -5;
           playSound('heavy');
           for(let i=1; i<3; i++) {
               const dist = i * 60;
               projectilesRef.current.push({
                   x: ent.x + (ent.facingRight ? dist : -dist), y: GROUND_Y, vx: 0, vy: 0,
