                                );
                            })}
                            {availableAbilities.length === 0 && <div className="col-span-full p-8 text-center text-gray-500 border-2 border-dashed border-gray-800 rounded-xl">No abilities available yet.</div>}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};
